import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"联动与排错","description":"","frontmatter":{},"headers":[],"relativePath":"gtcommission/compatibility.md","filePath":"gtcommission/compatibility.md","lastUpdated":1784248671000}'),l={name:"gtcommission/compatibility.md"};function n(p,s,h,d,o,c){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="联动与排错" tabindex="-1">联动与排错 <a class="header-anchor" href="#联动与排错" aria-label="Permalink to &quot;联动与排错&quot;">​</a></h1><p>GTCommission 的原版任务不需要安装额外插件。对应插件存在时，扩展任务会自动接入；没有安装的插件只会显示为未连接，不影响其他功能。</p><h2 id="mythicmobs" tabindex="-1">MythicMobs <a class="header-anchor" href="#mythicmobs" aria-label="Permalink to &quot;MythicMobs&quot;">​</a></h2><p>任务类型：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">KILL_MYTHIC</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SkeletalKnight</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">AngrySludge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><code>targets</code> 填 MythicMobs 怪物内部 ID，大小写不敏感。不要填显示名称、颜色代码或掉落表名称。</p><h2 id="gtmobdrops" tabindex="-1">GTMobDrops <a class="header-anchor" href="#gtmobdrops" aria-label="Permalink to &quot;GTMobDrops&quot;">​</a></h2><p>任务类型：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">GTMOBDROPS_OBTAIN</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">example_drop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>玩家通过 GTMobDrops 正常获得物品时增加进度。<code>targets</code> 填 GTMobDrops 物品或掉落配置中的内部 ID。</p><h2 id="gtgather" tabindex="-1">GTGather <a class="header-anchor" href="#gtgather" aria-label="Permalink to &quot;GTGather&quot;">​</a></h2><p>任务类型：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">GTGATHER</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">herb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>玩家完成采集后增加进度。<code>targets</code> 填 GTGather 采集模板 ID。</p><h2 id="副本通关" tabindex="-1">副本通关 <a class="header-anchor" href="#副本通关" aria-label="Permalink to &quot;副本通关&quot;">​</a></h2><p>统一任务类型：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">DUNGEON</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">castle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>已直接支持：</p><table tabindex="0"><thead><tr><th>副本插件</th><th>计入时机</th><th>可用目标</th></tr></thead><tbody><tr><td>DungeonPlus</td><td>副本以 <code>COMPLETE</code> 正常结束</td><td>副本名称、<code>DungeonPlus:名称</code></td></tr><tr><td>MythicDungeons</td><td>玩家触发通关事件</td><td>世界 ID、显示名、<code>MythicDungeons:ID</code></td></tr><tr><td>QueDP</td><td>副本触发完成事件</td><td>模板 ID、模板名称、<code>QueDP:ID</code></td></tr><tr><td>BTDungeons</td><td>副本以 <code>NORMAL</code> 原因结束</td><td>副本名称、<code>BTDungeons:名称</code></td></tr></tbody></table><p>插件会同时识别副本 ID、显示名称和带插件名前缀的写法。不同副本插件里有同名副本时，建议加前缀：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;DungeonPlus:castle&quot;</span></span></code></pre></div><p>同一场副本结束事件在短时间内重复触发时会自动去重，不会给同一名玩家重复增加通关次数。</p><h2 id="其他副本或脚本" tabindex="-1">其他副本或脚本 <a class="header-anchor" href="#其他副本或脚本" aria-label="Permalink to &quot;其他副本或脚本&quot;">​</a></h2><p>让副本结束动作执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtcommission progress {player} DUNGEON dungeon_id 1</span></span></code></pre></div><p>实际玩家变量按对应插件的写法替换。也可以通过 GT 系列动作提交：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>commission-progress:DUNGEON:dungeon_id:1</span></span></code></pre></div><p>自定义活动任务：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">CUSTOM</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">targets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">summer_event</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span></code></pre></div><p>再由活动插件执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtcommission progress 玩家 CUSTOM summer_event 1</span></span></code></pre></div><h2 id="物品库" tabindex="-1">物品库 <a class="header-anchor" href="#物品库" aria-label="Permalink to &quot;物品库&quot;">​</a></h2><p>提交任务和 GUI 图标可使用 GTCore 已接入的物品库。常见写法：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">objective</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  item</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mm:QuestCrystal&quot;</span></span></code></pre></div><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mm:QuestCrystal&quot;</span></span></code></pre></div><p>前缀和物品 ID 必须与服务器当前物品库一致。提交物品时会按实际物品数据匹配，不能只靠改名伪造。</p><h2 id="查看联动状态" tabindex="-1">查看联动状态 <a class="header-anchor" href="#查看联动状态" aria-label="Permalink to &quot;查看联动状态&quot;">​</a></h2><p>输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtcom debug</span></span></code></pre></div><p>输出中会列出：</p><ul><li>当前存储方式和跨服状态。</li><li>每种经济是否可用。</li><li>MythicMobs 是否已连接。</li><li>GTMobDrops、GTGather 和各副本插件是 <code>ACTIVE</code> 还是 <code>NOT_INSTALLED</code>。</li></ul><p>插件已经安装但仍显示 <code>NOT_INSTALLED</code> 时，先确认插件本身是否成功启用，再确认版本是否提供对应的完成事件。</p><h2 id="任务没有进度" tabindex="-1">任务没有进度 <a class="header-anchor" href="#任务没有进度" aria-label="Permalink to &quot;任务没有进度&quot;">​</a></h2><p>按以下顺序检查：</p><ol><li>玩家当前面板是否真的抽到了该任务。</li><li>任务、任务池和面板的 <code>conditions</code> 是否全部满足。</li><li><code>type</code> 是否与实际行为一致。</li><li><code>targets</code> 是否填写内部 ID，而不是中文显示名。</li><li>用 <code>/gtcommission progress 玩家 类型 目标 1</code> 手动提交一次。</li><li>用 <code>/gtcom debug</code> 查看联动状态。</li><li>打开 <code>debug: true</code> 后重载，再查看控制台记录。</li></ol><p>手动命令能增加进度，说明任务和面板配置没有问题，应继续检查对应插件是否触发了预期事件以及目标 ID 是否一致。</p><h2 id="gui-打不开" tabindex="-1">GUI 打不开 <a class="header-anchor" href="#gui-打不开" aria-label="Permalink to &quot;GUI 打不开&quot;">​</a></h2><ol><li>确认玩家数据已经加载，刚进服时稍等一秒再打开。</li><li>确认面板的 <code>gui</code> ID 在 <code>guis/commission/</code> 中存在。</li><li>检查矩阵是否每行 9 个字符、行数是否和 <code>size</code> 一致。</li><li>1.12 服务端使用新材质时填写 <code>legacy-material</code>。</li><li>执行 <code>/gtcom reload</code>，根据控制台报出的文件和节点修正。</li></ol><h2 id="经济不可用" tabindex="-1">经济不可用 <a class="header-anchor" href="#经济不可用" aria-label="Permalink to &quot;经济不可用&quot;">​</a></h2><p>输入 <code>/gtcom debug</code> 查看对应经济 ID：</p><ul><li>Vault：确认 Vault 和经济插件都已正常启用。</li><li>PlayerPoints、DreamPoints：确认插件已安装且版本可用。</li><li>自定义经济：确认 PlaceholderAPI 已安装，余额变量能返回纯数字，增减命令能由控制台执行。</li></ul><p>一条悬赏只能选择当前可用且被模板 <code>economies</code> 允许的经济。不可用经济不会出现在发布选择中。</p><h2 id="跨服不同步" tabindex="-1">跨服不同步 <a class="header-anchor" href="#跨服不同步" aria-label="Permalink to &quot;跨服不同步&quot;">​</a></h2><ol><li>所有子服必须选择相同的 <code>mysql</code> 或 <code>redis</code> 后端。</li><li>所有子服必须连接同一个数据库或 Redis 库。</li><li><code>storage.key-prefix</code> 必须一致。</li><li><code>storage.cross-server.enabled</code> 必须开启。</li><li>每个子服的 <code>server-id</code> 必须不同，或保持 <code>auto</code>。</li><li>用 <code>/gtcom debug</code> 确认没有回退到本地存储。</li></ol><p>连接失败时插件会优先保证服务器正常启动，并回退到本地数据。控制台会明确打印连接失败原因，此时不要继续让多个子服各自写本地数据，先修复远程存储连接。</p>`,55)])])}const g=i(l,[["render",n]]);export{k as __pageData,g as default};
